   134			t,
   135			dlsch0->rnti,
   136			proc->frame_rx,
   137			proc->nr_slot_rx,
   138			0,0);
   139	  }
   140	  switch (pdu_type){
   141	    case FAPI_NR_RX_PDU_TYPE_SIB:
   142	    case FAPI_NR_RX_PDU_TYPE_RAR:
   143	    case FAPI_NR_RX_PDU_TYPE_DLSCH:
   144	      if(dlsch0) {
   145	        dl_harq0 = &ue->dl_harq_processes[0][dlsch0->dlsch_config.harq_process_nbr];
   146	        rx_ind->rx_indication_body[n_pdus - 1].pdsch_pdu.harq_pid = dlsch0->dlsch_config.harq_process_nbr;
   147	        rx_ind->rx_indication_body[n_pdus - 1].pdsch_pdu.ack_nack = dl_harq0->ack;
   148	        rx_ind->rx_indication_body[n_pdus - 1].pdsch_pdu.pdu = b;
