   155	    case FAPI_NR_RX_PDU_TYPE_SSB: {
   156	        fapi_nr_ssb_pdu_t *ssb_pdu = &rx_ind->rx_indication_body[n_pdus - 1].ssb_pdu;
   157	        if(typeSpecific) {
   158	          NR_DL_FRAME_PARMS *frame_parms = &ue->frame_parms;
   159	          fapiPbch_t *pbch = (fapiPbch_t *)typeSpecific;
   160	          memcpy(ssb_pdu->pdu, pbch->decoded_output, sizeof(pbch->decoded_output));
   161	          ssb_pdu->additional_bits = pbch->xtra_byte;
   162	          ssb_pdu->ssb_index = (frame_parms->ssb_index) & 0x7;
   163	          ssb_pdu->ssb_length = frame_parms->Lmax;
   164	          ssb_pdu->cell_id = frame_parms->Nid_cell;
   165	          ssb_pdu->ssb_start_subcarrier = frame_parms->ssb_start_subcarrier;
   166	          ssb_pdu->rsrp_dBm = ue->measurements.ssb_rsrp_dBm[frame_parms->ssb_index];
   167	          ssb_pdu->radiolink_monitoring = RLM_in_sync; // TODO to be removed from here
   168	          ssb_pdu->decoded_pdu = true;
   169	        }
   170	        else {
   171	          ssb_pdu->radiolink_monitoring = RLM_out_of_sync; // TODO to be removed from here
   172	          ssb_pdu->decoded_pdu = false;
   173	        }
